    14→package labels
    15→
    16→import (
    17→	"bytes"
    18→	"strconv"
    19→)
    20→
    21→// MatchType is an enum for label matching types.
    22→type MatchType int
    23→
    24→// Possible MatchTypes.
    25→const (
    26→	MatchEqual MatchType = iota
    27→	MatchNotEqual
    28→	MatchRegexp
    29→	MatchNotRegexp
    30→)
    31→
    32→var matchTypeToStr = [...]string{
    33→	MatchEqual:     "=",
    34→	MatchNotEqual:  "!=",
    35→	MatchRegexp:    "=~",
    36→	MatchNotRegexp: "!~",
    37→}
    38→
    39→func (m MatchType) String() string {
    40→	if m < MatchEqual || m > MatchNotRegexp {
    41→		panic("unknown match type")
    42→	}
    43→	return matchTypeToStr[m]
    44→}
    45→
    46→// Matcher models the matching of a label.
    47→type Matcher struct {
    48→	Type  MatchType
    49→	Name  string
    50→	Value string
    51→
    52→	re *FastRegexMatcher
    53→}
    54→
    55→// NewMatcher returns a matcher object.
    56→func NewMatcher(t MatchType, n, v string) (*Matcher, error) {
    57→	m := &Matcher{
    58→		Type:  t,
    59→		Name:  n,
    60→		Value: v,
    61→	}
    62→	if t == MatchRegexp || t == MatchNotRegexp {
    63→		re, err := NewFastRegexMatcher(v)
    64→		if err != nil {
    65→			return nil, err
    66→		}
    67→		m.re = re
    68→	}
    69→	return m, nil
    70→}
    71→
    72→// MustNewMatcher panics on error - only for use in tests!
    73→func MustNewMatcher(mt MatchType, name, val string) *Matcher {
    74→	m, err := NewMatcher(mt, name, val)
    75→	if err != nil {
    76→		panic(err)
    77→	}
    78→	return m
    79→}
    80→
    81→func (m *Matcher) String() string {
    82→	// Start a buffer with a pre-allocated size on stack to cover most needs.
    83→	var bytea [1024]byte
    84→	b := bytes.NewBuffer(bytea[:0])
    85→
    86→	if m.shouldQuoteName() {
    87→		b.Write(strconv.AppendQuote(b.AvailableBuffer(), m.Name))
    88→	} else {
    89→		b.WriteString(m.Name)
    90→	}
    91→	b.WriteString(m.Type.String())
    92→	b.Write(strconv.AppendQuote(b.AvailableBuffer(), m.Value))
    93→
    94→	return b.String()
    95→}
    96→
    97→func (m *Matcher) shouldQuoteName() bool {
    98→	for i, c := range m.Name {
    99→		if c == '_' || (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (i > 0 && c >= '0' && c <= '9') {
   100→			continue
   101→		}
   102→		return true
   103→	}
   104→	return len(m.Name) == 0
   105→}
   106→
   107→// Matches returns whether the matcher matches the given string value.
   108→func (m *Matcher) Matches(s string) bool {
   109→	switch m.Type {
   110→	case MatchEqual:
   111→		return s == m.Value
   112→	case MatchNotEqual:
   113→		return s != m.Value
   114→	case MatchRegexp:
   115→		return m.re.MatchString(s)
   116→	case MatchNotRegexp:
   117→		return !m.re.MatchString(s)
   118→	}
   119→	panic("labels.Matcher.Matches: invalid match type")
   120→}
   121→
   122→// Inverse returns a matcher that matches the opposite.
   123→func (m *Matcher) Inverse() (*Matcher, error) {
   124→	switch m.Type {
   125→	case MatchEqual:
   126→		return NewMatcher(MatchNotEqual, m.Name, m.Value)
   127→	case MatchNotEqual:
   128→		return NewMatcher(MatchEqual, m.Name, m.Value)
   129→	case MatchRegexp:
   130→		return NewMatcher(MatchNotRegexp, m.Name, m.Value)
   131→	case MatchNotRegexp:
   132→		return NewMatcher(MatchRegexp, m.Name, m.Value)
   133→	}
   134→	panic("labels.Matcher.Matches: invalid match type")
   135→}
   136→
   137→// GetRegexString returns the regex string.
   138→func (m *Matcher) GetRegexString() string {
   139→	if m.re == nil {
   140→		return ""
   141→	}
   142→	return m.re.GetRegexString()
   143→}
   144→
   145→// SetMatches returns a set of equality matchers for the current regex matchers if possible.
   146→// For examples the regexp `a(b|f)` will returns "ab" and "af".
   147→// Returns nil if we can't replace the regexp by only equality matchers.
   148→func (m *Matcher) SetMatches() []string {
   149→	if m.re == nil {
   150→		return nil
   151→	}
   152→	return m.re.SetMatches()
   153→}
   154→
   155→// Prefix returns the required prefix of the value to match, if possible.
   156→// It will be empty if it's an equality matcher or if the prefix can't be determined.
   157→func (m *Matcher) Prefix() string {
   158→	if m.re == nil {
   159→		return ""
   160→	}
   161→	return m.re.prefix
   162→}
   163→
   164→// IsRegexOptimized returns whether regex is optimized.
   165→func (m *Matcher) IsRegexOptimized() bool {
   166→	if m.re == nil {
   167→		return false
   168→	}
   169→	return m.re.IsOptimized()
   170→}
